// Extract request data
const message = $json.body.message;
const characterId = $json.body.characterId || null;
const gameSessionId = $json.body.gameSessionId || null;
const conversationHistory = $json.body.conversationHistory || [];

// If characterId exists, fetch current game state
let currentGameState = null;

if (characterId) {
  try {
    // This would typically be done with HTTP Request nodes
    // For now, we'll structure the data for the AI
    currentGameState = {
      character: {
        id: characterId,
        // These would be fetched from the backend
      },
      gameSession: gameSessionId ? {
        id: gameSessionId,
        // These would be fetched from the backend
      } : null
    };
  } catch (error) {
    console.error('Failed to load game state:', error);
  }
}

// Prepare the context for the AI
return {
  message: message,
  characterId: characterId,
  gameSessionId: gameSessionId,
  conversationHistory: conversationHistory,
  currentGameState: currentGameState
};

// Extract AI response
const aiResponse = $json.response || $json.output || $json.message || '';

// Parse game state update from AI response
const jsonMatch = aiResponse.match(/```json\n([\s\S]*?)\n```/);
let gameStateUpdate = null;

if (jsonMatch) {
  try {
    gameStateUpdate = JSON.parse(jsonMatch[1]);
    console.log('Parsed game state update:', gameStateUpdate);
  } catch (e) {
    console.error('Failed to parse game state:', e);
  }
}

// Clean response text (remove JSON blocks)
const cleanResponse = aiResponse.replace(/```json[\s\S]*?```/g, '').trim();

// Get original request data
const originalData = $('Prepare Context').first().json;

return {
  aiResponseText: cleanResponse,
  gameStateUpdate: gameStateUpdate,
  characterId: originalData.characterId,
  gameSessionId: originalData.gameSessionId
};

